sql:
SELECT name, contact_name, phone, website, email, description
FROM neighborhood_associations
WHERE type_id = 0;

SELECT user_id, association_id, membership_status, joined_at, created_at, updated_at
FROM association_memberships
WHERE membership_status = 'Inactive';

external_knowledge:
- 'a lot of event attendance' refers to associations with more than 10 attendances; 
- 'active members' refers to members with a membership status of 'Active';
- 'sent campaign' refers to a campaign with a status of 'Sent'.

sql:
SELECT COUNT(*) AS number_of_campaigns
FROM texting_campaigns
WHERE association_id = 0;

SELECT campaign_name
FROM texting_campaigns
WHERE sent_at > '2023-05-30 00:00:00';

external_knowledge:
- 'Vibrant neighborhood associations' refers to associations that have at least one active member; 
- 'Dedicated members' refers to members with an 'Active' membership status; 
- 'A pulse' means having at least one active member.

sql:
SELECT COUNT(*) 
FROM association_memberships 
WHERE association_id = 0 AND membership_status = 'Active';

SELECT DISTINCT association_id
FROM texting_campaigns
WHERE status = 'Sent';

SELECT name
FROM neighborhood_associations
WHERE association_id = 1;

SELECT association_id, COUNT(*) as event_count
FROM association_events
GROUP BY association_id;

SELECT association_id, COUNT(*) AS number_of_campaigns
FROM texting_campaigns
GROUP BY association_id;

SELECT type_id, COUNT(*) AS association_count
FROM neighborhood_associations
GROUP BY type_id;
